/**
 * Tests for Auth Service
 */

import { AuthService } from "../../services/authService";
import { apiFetch, setToken, clearToken } from "../../services/api";
import { storage } from "../../services/storage";

// Mock dependencies
jest.mock("../../services/api", () => ({
  apiFetch: jest.fn(),
  setToken: jest.fn(),
  clearToken: jest.fn(),
}));

jest.mock("../../services/storage", () => ({
  storage: {
    get: jest.fn(),
    set: jest.fn(),
    remove: jest.fn(),
  },
}));

describe("AuthService", () => {
  let authService: AuthService;

  beforeEach(() => {
    jest.clearAllMocks();
    authService = new AuthService();
  });

  describe("login", () => {
    it("should login with username and password", async () => {
      const mockResponse = {
        user: { id: "user-1", username: "testuser", email: "test@test.com" },
        token: "access-token-123",
      };

      (apiFetch as jest.Mock).mockResolvedValue(mockResponse);

      const result = await authService.login("testuser", "password123");

      expect(apiFetch).toHaveBeenCalledWith("/auth/login", {
        method: "POST",
        body: JSON.stringify({ username: "testuser", password: "password123" }),
      });
      expect(storage.set).toHaveBeenCalledWith("auth_token", "access-token-123");
      expect(setToken).toHaveBeenCalledWith("access-token-123");
      expect(result.user.username).toBe("testuser");
    });

    it("should throw error if no token received", async () => {
      (apiFetch as jest.Mock).mockResolvedValue({ user: {} });

      await expect(
        authService.login("testuser", "password123"),
      ).rejects.toThrow("No token received from server");
    });
  });

  describe("getProfile", () => {
    it("should fetch user profile", async () => {
      const mockResponse = {
        data: {
          id: "user-1",
          username: "testuser",
          email: "test@test.com",
          roles: [{ name: "admin" }],
        },
      };

      (apiFetch as jest.Mock).mockResolvedValue(mockResponse);

      const result = await authService.getProfile();

      expect(apiFetch).toHaveBeenCalledWith("/auth/me");
      expect(result.username).toBe("testuser");
    });

    it("should throw if no user data received", async () => {
      (apiFetch as jest.Mock).mockResolvedValue({});

      await expect(authService.getProfile()).rejects.toThrow(
        "No user data received",
      );
    });
  });

  describe("logout", () => {
    it("should clear auth data", async () => {
      await authService.logout();

      expect(storage.remove).toHaveBeenCalledWith("auth_token");
      expect(clearToken).toHaveBeenCalled();
    });
  });

  describe("isAuthenticated", () => {
    it("should return false when no user", () => {
      expect(authService.isAuthenticated()).toBe(false);
    });

    it("should return true after login", async () => {
      const mockResponse = {
        user: { id: "user-1", username: "testuser" },
        token: "access-token-123",
      };

      (apiFetch as jest.Mock).mockResolvedValue(mockResponse);
      await authService.login("testuser", "password123");

      expect(authService.isAuthenticated()).toBe(true);
    });
  });
});
